import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.BIJDRAGE_WG_MTC;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.NETTO_KEY;

@Slf4j
public class BerekenInhoudingen extends AbstractRekenCommand {

    private FiscaleConstantService fiscaleConstantService;
    protected ConstantManager constantManager;

    public BerekenInhoudingen(ConstantManager constantManager, NlpGlobalService globalService) {
        this.constantManager = constantManager;
        this.fiscaleConstantService = globalService.getFiscaleConstantService();
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            for (Opper opper : opdracht.getOpperSlices()) {
                berekenInhoudingen(opdrachtContext, opper);

            }

            berekenVerminderingBvInhoudingen(opdrachtContext, opdracht);
        }
        return CONTINUE_PROCESSING;
    }

    private static final int KODE_MTC = 5401;

    protected void berekenInhoudingen(RekenContext context, Opper opper) {
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);
        List<NlpPrestatie> inhoudingen = context.getDoubleKey(INHOUDINGEN_KEY, opper);
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        LoonCodeManager loonCodeManager = context.getUnchecked(LOONCODE_MANAGER_KEY);
        Multimap<AardKodeExtensie, NlpPrestatie> inhoudingMap = vormInhoudingenMap(loonCodeManager, inhoudingen);

        for (AardKodeExtensie aardKodeExtensie : inhoudingMap.keySet()) {
            Collection<NlpPrestatie> lijst = inhoudingMap.get(aardKodeExtensie);

            Money totaalInhoudingBedrag = getTotaalInhoudingBedrag(context, opper, lijst, aardKodeExtensie, rekenTijd);
            log.debug("inhoudingBedrag:{}", totaalInhoudingBedrag);

            LoonElement element = new LoonElement(aardKodeExtensie);
            element.putProperty(NETTO_KEY, totaalInhoudingBedrag.negate());
            LocalDate startWgBijdrageMtc = constantManager.getByCodeDatum(Konstanten.KST_START_WG_BIJDRAGE_MTC, rekenTijd.eindDatum).getDatum();
            if (aardKodeExtensie.getCode() == KODE_MTC && !rekenTijd.beginDatum.isBefore(startWgBijdrageMtc)) {
                Money wgBijdrageMtc = getWerkgeverBijdrageMaaltijdCheques(lijst, aardKodeExtensie, rekenTijd);
                element.putProperty(BIJDRAGE_WG_MTC, wgBijdrageMtc);
            }
            manager.addLoonElement(element, opper);
        }
    }

    protected Multimap<AardKodeExtensie, NlpPrestatie> vormInhoudingenMap(LoonCodeManager loonCodeManager, List<NlpPrestatie> inhoudingen) {
        Multimap<AardKodeExtensie, NlpPrestatie> inhoudingMap = ArrayListMultimap.create();
        for (NlpPrestatie inhouding : inhoudingen) {
            AardKodeExtensie aardKodeExtensie = loonCodeManager.getByPrestatie(inhouding);
            if (!aardKodeExtensie.behoortTotGroep(INH_WERKUITKERING_UREN_KEY) && !aardKodeExtensie.behoortTotGroep(INHOUDING_VOORSCHOT_KEY)
                    && !aardKodeExtensie.behoortTotGroep(BETALING_VOORSCHOT_KEY)) {
                inhoudingMap.put(aardKodeExtensie, inhouding);
            }
        }
        return inhoudingMap;
    }

    private Money getTotaalInhoudingBedrag(
            RekenContext context, Opper opper, Collection<NlpPrestatie> lijst, AardKodeExtensie aardKodeExtensie,
            RekenTijd rekenTijd) {
        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        KedefFormuletype formuleType = aardKodeExtensie.getFormuleType();
        log.debug("inhouding looncode:{}; formuleType:{}", aardKodeExtensie, formuleType);

        Money totaalInhoudingBedrag = Money.ZERO;
        for (NlpPrestatie inhouding : lijst) {
            log.debug("inhouding prestatie:{}", LogTools.toLogInhouding(inhouding));
            Money inhoudingBedrag = getInhoudingBedrag(context, opper, inhouding, aardKodeExtensie, rekenTijd, regulManager);
            totaalInhoudingBedrag = totaalInhoudingBedrag.add(inhoudingBedrag);
        }
        return totaalInhoudingBedrag;
    }

    private Money getWerkgeverBijdrageMaaltijdCheques(Collection<NlpPrestatie> lijst, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        Money totaalBedrag = Money.ZERO;
        for (NlpPrestatie inhouding : lijst) {
            Money basisBedrag = constantManager.getByCodeDatum(aardKodeExtensie.getConst3nr(), rekenTijd.eindDatum).getMoney();
            Money bedrag = basisBedrag.multiply(inhouding.getX()).round(2);
            totaalBedrag = totaalBedrag.add(bedrag);
        }
        return totaalBedrag;
    }

    private Money getInhoudingBedrag(
            RekenContext context, Opper opper, NlpPrestatie inhouding, AardKodeExtensie aardKodeExtensie,
            RekenTijd rekenTijd, RegulManager regulManager) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Indexator indexator = context.getUnchecked(INDEXATOR_KEY);
        KedefFormuletype formuleType = aardKodeExtensie.getFormuleType();
        Money inhoudingBedrag = Money.ZERO;
        switch (formuleType) {
            case INH_WN:
                inhoudingBedrag = getInhoudingBedragWerknemer(inhouding);
                break;
            case INH_WG:
                inhoudingBedrag = getInhoudingBedragWerkgever(inhouding, aardKodeExtensie, rekenTijd);
                break;
            case INH_WG_PCT_BB_TOT:
                inhoudingBedrag = getInhoudingBedragWerkgeverPctBbTot(manager, opper, inhouding, aardKodeExtensie, rekenTijd);
                break;
            case INH_WG_PCT_BR_V1:
                inhoudingBedrag = getInhoudingBedragWerkgeverPctBrV1(manager, opper, inhouding, aardKodeExtensie, rekenTijd);
                break;
            case INH_WG_PCT_TB:
                inhoudingBedrag = getInhoudingBedragWerkgeverPctTb(context, opper, inhouding, aardKodeExtensie, rekenTijd);
                break;
            case INH_WG_PCT_BR_TOT:
                inhoudingBedrag = getInhoudingBedragWerkgeverPctBrTot(context, opper, inhouding, aardKodeExtensie, rekenTijd);
                break;
            case INH_WG_PCT_BB_GEWOON:
                inhoudingBedrag = getInhoudingBedragWerkgeverPctBbGewoon(manager, opper, inhouding, aardKodeExtensie, rekenTijd);
                break;
            case INH_WG_PCT_NETTO:
                inhoudingBedrag = getInhoudingBedragWerkgeverPctNetto(manager, opper.getOpdracht(), inhouding, aardKodeExtensie, rekenTijd);
                break;
            default:
                regulManager.doRegulException(opper.getOpdracht(), Regulkode.FORMULETYPE_NIET_GEPROGRAMMEERD);
                break;
        }
        return indexator.indexeer(inhoudingBedrag, aardKodeExtensie, opper).round(2);
    }

    private Money getInhoudingBedragWerknemer(NlpPrestatie inhouding) {
        return inhouding.getY().multiply(inhouding.getX());
    }

    private Money getInhoudingBedragWerkgever(NlpPrestatie inhouding, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        Money basisBedrag = constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), rekenTijd.eindDatum).getMoney();
        return basisBedrag.multiply(inhouding.getX());
    }

    private Money getInhoudingBedragWerkgeverPctBbTot(
            LoonElementManager manager, Opper opper, NlpPrestatie inhouding,
            AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
        if (isInhoudingPartijkasTotBbUitgezonderdSocialeBijdrageNbMandataris(inhouding)) {
            loonElementen = loonElementen.stream().filter(x -> !isTerubetalingSocialeBijdragenNietBeschermdMandataris(x.getAardKodeExtensie()))
                    .collect(Collectors.toList());
        }
        Money totaalBelastbaar = getTotaalBelastbaar(loonElementen);
        BigDecimal percentage = constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), rekenTijd.eindDatum).getProcentFactor();
        return totaalBelastbaar.multiply(inhouding.getX()).multiply(percentage);
    }

    private Money getInhoudingBedragWerkgeverPctBrV1(
            LoonElementManager manager, Opper opper, NlpPrestatie inhouding,
            AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
        Money verzamelStaatBruto = Money.ZERO;
        for (LoonElement loonElement : loonElementen) {
            Loontype loontype = Loontype.getByCode(loonElement.getAardKodeExtensie().getLoontype());
            if (loontype == Loontype.NORMAAL_LN) {
                verzamelStaatBruto = verzamelStaatBruto.add(loonElement.getPropertyMoney(BRUTO_MAANDLOON_KEY));
            }
        }
        BigDecimal percentage = constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), rekenTijd.eindDatum).getProcentFactor();
        return verzamelStaatBruto.multiply(inhouding.getX()).multiply(percentage).round(2, RoundingMode.FLOOR);
    }

    private Money getInhoudingBedragWerkgeverPctTb(
            RekenContext context, Opper opperIn, NlpPrestatie inhouding, AardKodeExtensie aardKodeExtensie,
            RekenTijd rekenTijd) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Opdracht opdracht = opperIn.getOpdracht();
        Money theoretischBruto = Money.ZERO;
        for (Opper opper : opdracht.getOpperSlices()) {
            Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
            for (LoonElement loonElement : loonElementen) {
                Money basisBedrag = loonElement.getPropertyMoney(BASIS_BEDRAG_KEY);
                theoretischBruto = theoretischBruto.add(basisBedrag);
            }
        }
        BigDecimal percentage = constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), rekenTijd.eindDatum).getProcentFactor();
        return theoretischBruto.multiply(inhouding.getX()).multiply(percentage);
    }

    private Money getInhoudingBedragWerkgeverPctBrTot(
            RekenContext context, Opper opper, NlpPrestatie inhouding, AardKodeExtensie aardKodeExtensie,
            RekenTijd rekenTijd) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opper.getOpdracht());
        if (isInhoudingPartijkasTotBrutoUitgezonderdSocialeBijdrageNbMandataris(inhouding)) {
            loonElementen = loonElementen.stream().filter(x -> !isTerubetalingSocialeBijdragenNietBeschermdMandataris(x.getAardKodeExtensie()))
                    .collect(Collectors.toList());
        }
        Money totaalBruto = Money.ZERO;
        for (LoonElement loonElement : loonElementen) {
            Money bruto = loonElement.getPropertyMoney(BRUTO_MAANDLOON_KEY);
            AardKodeExtensie loonCode = loonElement.getAardKodeExtensie();

            if (!loonCode.getAard().equals(AardKodeExt.I_KODE_EXT.getCode()) && (!aardKodeExtensie.behoortTotGroep(INH_PERS_BIJDRAGE_GROEPSVERZ_KEY)
                    || !loonCode.behoortTotGroep(EXCL_PERS_BIJDRAGE_GROEPSVERZ_KEY))) {
                totaalBruto = totaalBruto.add(bruto);
            }
        }
        BigDecimal percentage = constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), rekenTijd.eindDatum).getProcentFactor();

        return totaalBruto.multiply(inhouding.getX()).multiply(percentage);
    }

    private Money getInhoudingBedragWerkgeverPctBbGewoon(
            LoonElementManager manager, Opper opper, NlpPrestatie inhouding,
            AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
        Money totaalGewoonBelastbaar = getBelastbaarGewoneBezoldigingen(loonElementen);
        BigDecimal percentage = constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), rekenTijd.eindDatum).getProcentFactor();
        return totaalGewoonBelastbaar.multiply(inhouding.getX()).multiply(percentage);
    }

    private Money getInhoudingBedragWerkgeverPctNetto(
            LoonElementManager manager, Opdracht opdracht, NlpPrestatie inhouding,
            AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        Money totaalNetto = Money.ZERO;
        for (LoonElement element : loonElementen) {
            if (element.getAardKodeExtensie().getAard() != AardKodeExt.I_KODE_EXT.getCode().intValue()) {
                totaalNetto = totaalNetto.add(element.getPropertyMoney(NETTO_KEY));
            }
        }

        BigDecimal percentage = constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), rekenTijd.eindDatum).getProcentFactor();
        return totaalNetto.multiply(inhouding.getX()).multiply(percentage);
    }

    private void berekenVerminderingBvInhoudingen(RekenContext context, Opdracht opdracht) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        SortedSet<LoonElement> inhoudingenVerminderingBv = LoonElement.createSortedSet();
        for (LoonElement element : loonElementen) {
            AardKodeExtensie aardKodeExtensie = element.getAardKodeExtensie();
            if (aardKodeExtensie.behoortTotGroep(INH_MET_VERM_BV_KEY)) {
                inhoudingenVerminderingBv.add(element);
            }
        }
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);
        if (!rekenTijd.isAchterstal) {
            berekenVerminderingBvInhoudingenGewoon(context, opdracht, inhoudingenVerminderingBv);
        } else {
            berekenVerminderingBvInhoudingenAchterstal(context, opdracht, inhoudingenVerminderingBv);
        }

        for (LoonElement inhouding : inhoudingenVerminderingBv) {
            inhouding.addToProperty(NETTO_KEY, inhouding.getPropertyMoney(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_10_KEY));
            inhouding.addToProperty(NETTO_KEY, inhouding.getPropertyMoney(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_18_KEY));
        }
    }

    private void berekenVerminderingBvInhoudingenGewoon(RekenContext context, Opdracht opdracht, SortedSet<LoonElement> inhoudingenVerminderingBv) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Integer fiscaalJaar = context.getInteger(FISCAAL_JAAR_KEY);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        Money totaalInhoudingBedrag = RekenTools.getSomProperty(NETTO_KEY, inhoudingenVerminderingBv);
        if (totaalInhoudingBedrag.signum() != 0) {
            Money bvFiche10 = Money.ZERO;
            Money bvFiche18 = Money.ZERO;
            for (LoonElement element : loonElementen) {
                Money bvGewoon = element.getPropertyMoney(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY);
                FiskFiche fiche = BvTools.regimeToFiche(element.getRegimeBv(), fiscaalJaar);
                if (fiche == FiskFiche.FISK_FICHE_281_10) {
                    bvFiche10 = bvFiche10.add(bvGewoon);
                } else if (fiche == FiskFiche.FISK_FICHE_281_18) {
                    bvFiche18 = bvFiche18.add(bvGewoon);
                }
            }

            RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);
            FiscaleConstant fiscaleConstanten = getFiscaleConstanten(rekenTijd);
            BigDecimal percentage = fiscaleConstanten.getPercentageVerminderingGroepsVerzekering().movePointLeft(2);
            Money verminderingBv = totaalInhoudingBedrag.multiply(percentage).round(2).negate();
            Money verminderingBv10 = verminderingBv.min(bvFiche10);
            Money verminderingBv18 = (verminderingBv.subtract(verminderingBv10)).min(bvFiche18);
            log.debug("verminderingBv10:{}", verminderingBv10);
            log.debug("verminderingBv18:{}", verminderingBv18);
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_10_KEY, verminderingBv10, NETTO_KEY, totaalInhoudingBedrag,
                    inhoudingenVerminderingBv);
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_18_KEY, verminderingBv18, NETTO_KEY, totaalInhoudingBedrag,
                    inhoudingenVerminderingBv);
        }
    }

    private void berekenVerminderingBvInhoudingenAchterstal(RekenContext context, Opdracht opdracht, SortedSet<LoonElement> inhoudingenVerminderingBv) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Money totaalInhoudingBedrag = RekenTools.getSomProperty(NETTO_KEY, inhoudingenVerminderingBv);
        RekenContext preBerekeningContext = context.getUnchecked(PRE_BEREKENING_CONTEXT_VORIG_FISCAAL_JAAR_KEY);
        LoonElementManager prevLoonElementManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> prevLoonElementen = prevLoonElementManager.getOpdrachtsElementen(opdracht);
        if (inhoudingenVerminderingBv.isEmpty() || totaalInhoudingBedrag.signum() == 0) {
            SortedSet<LoonElement> nieuweElementen = overnemenBvInhoudingenVorigeBerekening(opdracht, manager, prevLoonElementen);
            inhoudingenVerminderingBv.addAll(nieuweElementen);
        } else {
            Money prevVerminderingBv10 = Money.ZERO;
            Money prevVerminderingBv18 = Money.ZERO;
            for (LoonElement element : prevLoonElementen) {
                AardKodeExtensie aardKodeExtensie = element.getAardKodeExtensie();
                if (aardKodeExtensie.behoortTotGroep(INH_MET_VERM_BV_KEY)) {
                    prevVerminderingBv10 = prevVerminderingBv10.add(element.getPropertyMoney(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_10_KEY));
                    prevVerminderingBv18 = prevVerminderingBv18.add(element.getPropertyMoney(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_18_KEY));
                }
            }
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_10_KEY, prevVerminderingBv10, NETTO_KEY, totaalInhoudingBedrag,
                    inhoudingenVerminderingBv);
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_18_KEY, prevVerminderingBv18, NETTO_KEY, totaalInhoudingBedrag,
                    inhoudingenVerminderingBv);
        }
    }

    private SortedSet<LoonElement> overnemenBvInhoudingenVorigeBerekening(
            Opdracht opdracht, LoonElementManager manager,
            Collection<LoonElement> prevElementen) {
        SortedSet<LoonElement> nieuweElementen = LoonElement.createSortedSet();
        for (LoonElement element : prevElementen) {
            AardKodeExtensie aardKodeExtensie = element.getAardKodeExtensie();
            if (aardKodeExtensie.behoortTotGroep(INH_MET_VERM_BV_KEY)) {
                Opper opper = RekenTools.findOpper(opdracht, element.getOpper().getActualTo());
                LoonElement nieuw = manager.getLoonElement(aardKodeExtensie, opper, null);
                if (nieuw == null) {
                    nieuw = new LoonElement(aardKodeExtensie);
                    manager.addLoonElement(nieuw, opper);
                }

                nieuw.copyProperty(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_10_KEY, element);
                nieuw.copyProperty(VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_18_KEY, element);
                nieuweElementen.add(nieuw);
            }
        }
        return nieuweElementen;
    }

    private FiscaleConstant getFiscaleConstanten(RekenTijd rekenTijd) {
        LocalDate taxdatum;
        if (!rekenTijd.isAchterstal) {
            taxdatum = rekenTijd.eindDatum;
        } else {
            taxdatum = rekenTijd.rekenDatum.dayOfMonth().withMaximumValue();
        }
        log.debug("{} taxDatum:{}", this.getClass().getSimpleName(), taxdatum);
        return fiscaleConstantService.getByDate(taxdatum);
    }

    private static final Set<LnedefRegBv> REGIMES_BV_NIET_BELASTBAAR =
            Sets.immutableEnumSet(LnedefRegBv.VD_BV_10_KWG__NBB, LnedefRegBv.VD_BV_50_KOSTEN_NBB, LnedefRegBv.VD_BV_50_VAC_TOE_NBB,
                    LnedefRegBv.VD_BV_10_FTSW_NBB, LnedefRegBv.VD_BV_10_MOB_VERG_NBB, LnedefRegBv.NBB_NFF);

    private Money getTotaalBelastbaar(Collection<LoonElement> loonElementen) {
        Money totaalBelastbaar = Money.ZERO;
        for (LoonElement element : loonElementen) {
            LnedefRegBv regimeBv = element.getRegimeBv();
            if (!REGIMES_BV_NIET_BELASTBAAR.contains(regimeBv)) {
                Money belastbaar = element.getPropertyMoney(BELASTBAAR_KEY);
                totaalBelastbaar = totaalBelastbaar.add(belastbaar);
            }
        }
        return totaalBelastbaar;
    }

    private Money getBelastbaarGewoneBezoldigingen(Collection<LoonElement> loonElementen) {
        Money belastbaar = Money.ZERO;
        for (LoonElement element : loonElementen) {
            LnedefRegBv regimeBv = element.getRegimeBv();
            if (regimeBv == LnedefRegBv.VD_BV_10_BZ___GB) {
                belastbaar = belastbaar.add(element.getPropertyMoney(BELASTBAAR_KEY));
            }
        }
        return belastbaar;
    }

    private boolean isTerubetalingSocialeBijdragenNietBeschermdMandataris(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getCode() == 1100 && (aardKodeExtensie.getExtensie() == 3 || aardKodeExtensie.getExtensie() == 4);
    }

    private boolean isInhoudingPartijkasTotBbUitgezonderdSocialeBijdrageNbMandataris(NlpPrestatie inhouding) {
        return inhouding.getCode() == 5503 && inhouding.getExtensie() >= 41 && inhouding.getExtensie() <= 45;
    }

    private boolean isInhoudingPartijkasTotBrutoUitgezonderdSocialeBijdrageNbMandataris(NlpPrestatie inhouding) {
        return inhouding.getCode() == 5503 && inhouding.getExtensie() >= 46 && inhouding.getExtensie() <= 50;
    }
